// 1. Configuración del límite de cupos (puedes cambiar este número)
const MAX_CUPOS = 2; 

// 2. Obtener todos los registros devueltos por Google Sheets
const registros = $input.all(); 
let totalActivos = 0;

// 3. Iterar sobre cada registro para contar los 'activos'
registros.forEach(fila => {
    // Se extrae el valor asumiendo que la columna se llama exactamente 'estado'
const estadoActual = fila.json.Estado ? fila.json.Estado.toString().toLowerCase().trim() : "";

    if (estadoActual === 'activo') {
        totalActivos++;
    }
});

// 4. Evaluar disponibilidad
const hayCupo = totalActivos < MAX_CUPOS;

// 5. Retornar un único objeto con el resumen de la validación
return [{
    json: {
        limite: MAX_CUPOS,
        inscritosActivos: totalActivos,
        cuposRestantes: MAX_CUPOS - totalActivos,
        aprobado: hayCupo
    }
}];

